export type FlowPluginRequirements = ClientWithRpc<
  GetAccountInfoApi & GetMultipleAccountsApi
> &
  ClientWithPayer &
  ClientWithTransactionPlanning &
  ClientWithTransactionSending;

export function flowProgram() {
  return <T extends FlowPluginRequirements>(
    client: T,
  ): ExtendedClient<T, { flow: FlowPlugin }> => {
    return extendClient(client, {
      flow: <FlowPlugin>{
        accounts: {
          gameState: addSelfFetchFunctions(client, getGameStateCodec()),
          playerAccount: addSelfFetchFunctions(client, getPlayerAccountCodec()),
          sessionTokenV2: addSelfFetchFunctions(
            client,
            getSessionTokenV2Codec(),
          ),
        },
        instructions: {
          cancelGame: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getCancelGameInstructionAsync(input),
            ),
          commitAndSettle: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getCommitAndSettleInstruction(input),
            ),
          createGame: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getCreateGameInstructionAsync(input),
            ),
          delegateAccount: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getDelegateAccountInstructionAsync({
                ...input,
                payer: input.payer ?? client.payer,
              }),
            ),
          joinGame: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getJoinGameInstructionAsync(input),
            ),
          pass: (input) =>
            addSelfPlanAndSendFunctions(client, getPassInstruction(input)),
          processUndelegation: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getProcessUndelegationInstruction({
                ...input,
                payer: input.payer ?? client.payer.address,
              }),
            ),
          scheduleTick: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getScheduleTickInstructionAsync({
                ...input,
                payer: input.payer ?? client.payer,
              }),
            ),
          settle: (input) =>
            addSelfPlanAndSendFunctions(
              client,
              getSettleInstructionAsync(input),
            ),
          startGame: (input) =>
            addSelfPlanAndSendFunctions(client, getStartGameInstruction(input)),
          tickPrice: (input) =>
            addSelfPlanAndSendFunctions(client, getTickPriceInstruction(input)),
        },
        pdas: {
          vault: findVaultPda,
          game: findGamePda,
          player: findPlayerPda,
          bufferPda: findBufferPdaPda,
          delegationRecordPda: findDelegationRecordPdaPda,
          delegationMetadataPda: findDelegationMetadataPdaPda,
          playerAccount: findPlayerAccountPda,
        },
        identifyAccount: identifyFlowAccount,
        identifyInstruction: identifyFlowInstruction,
        parseInstruction: parseFlowInstruction,
      },
    });
  };
}

type MakeOptional<T, K extends keyof T> = Omit<T, K> & Partial<Pick<T, K>>;
